/**
 * SafeKid — TikTok Platform Adapter
 * Selectors, URL patterns, and data extractors for tiktok.com.
 *
 * TikTok uses `data-e2e` attributes extensively which are more stable
 * than CSS class names (generated by CSS-in-JS and rotated frequently).
 * All selectors prioritise `data-e2e` with generic fallbacks.
 */

const TikTokPlatform = {
  platform: 'tiktok',

  // ==================== SELECTORS ====================

  /** Video item containers in the feed / search / profile */
  videoItemSelectors: [
    '[data-e2e="recommend-list-item-container"]',
    '[data-e2e="user-post-item"]',
    '[data-e2e="user-post-item-list"] > div',
    '[data-e2e="search-card-container"]',
    '[data-e2e="search-common-link"]'
  ],

  /** Author / channel username selectors inside a video item */
  channelSelectors: [
    '[data-e2e="video-author-uniqueid"]',
    '[data-e2e="feed-author-nickname"]',
    'a[href^="/@"]'
  ],

  /** Video player selectors */
  playerSelector: '[data-e2e="video-player"], video',

  /** Video description */
  descriptionSelector: '[data-e2e="video-desc"]',

  /** Browse / detail page username */
  browseUsernameSelector: '[data-e2e="browse-username"], h3[data-e2e="video-author-uniqueid"]',

  /** Navigation events to watch */
  navigationEvents: ['popstate'],

  // ==================== EXTRACTORS ====================

  /**
   * Extract @username from a video item element.
   * Returns the raw username WITHOUT leading @, lower-cased.
   * @param {Element} el — video item container
   * @returns {string|null}
   */
  extractUsername(el) {
    if (!el) return null;

    // 1. data-e2e author element
    for (const sel of this.channelSelectors) {
      const authorEl = el.querySelector(sel);
      if (authorEl) {
        // Prefer textContent for uniqueid element
        const text = (authorEl.textContent || '').trim();
        if (text) return this.normalizeUsername(text);

        // Fallback: extract from href
        const href = authorEl.getAttribute('href') || '';
        const match = href.match(/^\/@([^/?#]+)/);
        if (match) return this.normalizeUsername(match[1]);
      }
    }

    // 2. Any link to a profile
    const profileLink = el.querySelector('a[href^="/@"]');
    if (profileLink) {
      const href = profileLink.getAttribute('href') || '';
      const match = href.match(/^\/@([^/?#]+)/);
      if (match) return this.normalizeUsername(match[1]);
    }

    return null;
  },

  /**
   * Extract video ID from a video item element or the current URL.
   * TikTok video IDs are numeric strings (typically 19 digits).
   * @param {Element} el
   * @returns {string|null}
   */
  extractVideoId(el) {
    if (!el) return null;

    // Link inside the element
    const links = el.querySelectorAll('a[href]');
    for (const link of links) {
      const href = link.getAttribute('href') || '';
      const match = href.match(/\/@[^/]+\/video\/(\d+)/);
      if (match) return match[1];
    }

    return null;
  },

  /**
   * Extract video ID from an arbitrary URL string.
   * @param {string} url
   * @returns {string|null}
   */
  extractVideoIdFromUrl(url) {
    try {
      const match = (url || '').match(/\/@[^/]+\/video\/(\d+)/);
      return match ? match[1] : null;
    } catch {
      return null;
    }
  },

  /**
   * Get the @username visible on the current page URL.
   * Works on profile pages (`/@user`) and video pages (`/@user/video/ID`).
   * @returns {string|null}
   */
  getPageUsername() {
    const match = location.pathname.match(/^\/@([^/?#]+)/);
    return match ? this.normalizeUsername(match[1]) : null;
  },

  /**
   * Determine the current page context on TikTok.
   * @returns {'feed'|'video'|'profile'|'search'|'following'|'explore'|'other'}
   */
  getPageContext() {
    const path = location.pathname;
    if (path.match(/^\/@[^/]+\/video\/\d+/)) return 'video';
    if (path.match(/^\/@[^/]+/)) return 'profile';
    if (path.startsWith('/search')) return 'search';
    if (path === '/following') return 'following';
    if (path === '/explore') return 'explore';
    if (path === '/' || path === '/foryou' || path === '') return 'feed';
    return 'other';
  },

  // ==================== HELPERS ====================

  /**
   * Normalize a TikTok username: lower-case, strip leading @, trim.
   * @param {string} raw
   * @returns {string}
   */
  normalizeUsername(raw) {
    return (raw || '').trim().replace(/^@/, '').toLowerCase();
  }
};

// Export for content scripts
if (typeof globalThis !== 'undefined') {
  globalThis.TikTokPlatform = TikTokPlatform;
}
